import { createHash, randomBytes } from 'crypto'

// Libsodium is async ΓÇö call initCrypto() once before using anything
let sodium: typeof import('libsodium-wrappers') | null = null

export async function initCrypto(): Promise<void> {
  if (sodium) return
  const lib = await import('libsodium-wrappers')
  await lib.ready
  sodium = lib
}

function getSodium() {
  if (!sodium) throw new Error('Crypto not initialized. Call initCrypto() first.')
  return sodium
}

export interface SigningKeyPair {
  publicKey: string  // base64
  privateKey: string // base64
}

export interface ExchangeKeyPair {
  publicKey: string  // base64
  privateKey: string // base64
}

export interface EncryptedPacket {
  ciphertext: string // base64
  nonce: string      // base64
  signature: string  // base64
}

// Generate Ed25519 signing key pair
export async function generateSigningKeyPair(): Promise<SigningKeyPair> {
  await initCrypto()
  const s = getSodium()
  const pair = s.crypto_sign_keypair()
  return {
    publicKey: Buffer.from(pair.publicKey).toString('base64'),
    privateKey: Buffer.from(pair.privateKey).toString('base64')
  }
}

// Generate X25519 key exchange pair
export async function generateExchangeKeyPair(): Promise<ExchangeKeyPair> {
  await initCrypto()
  const s = getSodium()
  const pair = s.crypto_box_keypair()
  return {
    publicKey: Buffer.from(pair.publicKey).toString('base64'),
    privateKey: Buffer.from(pair.privateKey).toString('base64')
  }
}

// Encrypt message with ChaCha20-Poly1305 + Ed25519 signature
export async function encryptMessage(
  plaintext: string,
  sessionKey: Uint8Array,
  signingPrivateKey: Uint8Array
): Promise<EncryptedPacket> {
  await initCrypto()
  const s = getSodium()

  const nonce = randomBytes(s.crypto_secretbox_NONCEBYTES)
  const plaintextBytes = Buffer.from(plaintext, 'utf-8')

  const ciphertext = s.crypto_secretbox_easy(plaintextBytes, nonce, sessionKey)

  // Sign ciphertext + nonce together
  const toSign = Buffer.concat([Buffer.from(ciphertext), nonce])
  const signature = s.crypto_sign_detached(toSign, signingPrivateKey)

  return {
    ciphertext: Buffer.from(ciphertext).toString('base64'),
    nonce: Buffer.from(nonce).toString('base64'),
    signature: Buffer.from(signature).toString('base64')
  }
}

// Verify signature + decrypt
export async function decryptMessage(
  packet: EncryptedPacket,
  sessionKey: Uint8Array,
  signingPublicKey: Uint8Array
): Promise<string> {
  await initCrypto()
  const s = getSodium()

  const ciphertext = Buffer.from(packet.ciphertext, 'base64')
  const nonce = Buffer.from(packet.nonce, 'base64')
  const signature = Buffer.from(packet.signature, 'base64')

  // Verify BEFORE decrypting
  const toVerify = Buffer.concat([ciphertext, nonce])
  const valid = s.crypto_sign_verify_detached(signature, toVerify, signingPublicKey)
  if (!valid) throw new Error('Signature verification failed ΓÇö message may be tampered.')

  const plaintext = s.crypto_secretbox_open_easy(ciphertext, nonce, sessionKey)
  if (!plaintext) throw new Error('Decryption failed.')

  return Buffer.from(plaintext).toString('utf-8')
}

// X25519 ECDH ΓÇö derive shared session key
export async function deriveSessionKey(
  myPrivateKey: Uint8Array,
  theirPublicKey: Uint8Array
): Promise<Uint8Array> {
  await initCrypto()
  const s = getSodium()
  return s.crypto_scalarmult(myPrivateKey, theirPublicKey)
}

// Sign arbitrary payload
export async function signPayload(
  payload: Uint8Array,
  privateKey: Uint8Array
): Promise<Uint8Array> {
  await initCrypto()
  return getSodium().crypto_sign_detached(payload, privateKey)
}

// Verify arbitrary payload
export async function verifySignature(
  payload: Uint8Array,
  signature: Uint8Array,
  publicKey: Uint8Array
): Promise<boolean> {
  await initCrypto()
  return getSodium().crypto_sign_verify_detached(signature, payload, publicKey)
}

// SHA-256 fingerprint of two public keys concatenated
export function computeFingerprint(edPub: string, xPub: string): string {
  return createHash('sha256')
    .update(Buffer.from(edPub + xPub))
    .digest('hex')
}

// Safely zero out a buffer
export function zeroize(buf: Buffer): void {
  buf.fill(0)
}

import { randomBytes, scryptSync, timingSafeEqual } from 'crypto'
import { app } from 'electron'
import fs from 'fs'
import path from 'path'

export interface IdentityProfile {
  displayName: string
  statusLine: string
  publicId: string
}

interface IdentityRecord {
  version: 1
  profile: IdentityProfile
  passcodeSalt: string
  passcodeHash: string
  createdAt: number
  updatedAt: number
}

export interface IdentityState {
  hasIdentity: boolean
  isUnlocked: boolean
  profile: IdentityProfile | null
}

let isUnlocked = false

export function getDataDir(): string {
  return path.join(app.getPath('userData'), 'anon-chat')
}

function getIdentityFile(): string {
  return path.join(getDataDir(), 'identity.json')
}

function ensureDataDir(): void {
  fs.mkdirSync(getDataDir(), { recursive: true })
}

function generatePublicId(): string {
  return `anon-${randomBytes(4).toString('hex')}-${randomBytes(4).toString('hex')}`
}

function normalizeName(s: string, max: number): string {
  return s.trim().replace(/\s+/g, ' ').slice(0, max)
}

function hashPasscode(passcode: string, saltBase64: string): string {
  return scryptSync(passcode, Buffer.from(saltBase64, 'base64'), 64).toString('base64')
}

function readIdentity(): IdentityRecord | null {
  ensureDataDir()
  const file = getIdentityFile()
  if (!fs.existsSync(file)) return null
  try {
    return JSON.parse(fs.readFileSync(file, 'utf-8')) as IdentityRecord
  } catch {
    return null
  }
}

function writeIdentity(identity: IdentityRecord): void {
  ensureDataDir()
  fs.writeFileSync(getIdentityFile(), JSON.stringify(identity, null, 2), { mode: 0o600 })
}

function makeState(identity: IdentityRecord | null): IdentityState {
  return {
    hasIdentity: Boolean(identity),
    isUnlocked,
    profile: isUnlocked && identity ? identity.profile : null
  }
}

export function getIdentityState(): IdentityState {
  return makeState(readIdentity())
}

export function requireUnlocked(): void {
  if (!isUnlocked) throw new Error('Unlock the app to continue.')
}

export function getIdentityProfile(): IdentityProfile {
  requireUnlocked()
  const identity = readIdentity()
  if (!identity) throw new Error('No local identity found.')
  return identity.profile
}

export function createIdentity(payload: {
  displayName: string
  statusLine: string
  passcode: string
}): IdentityState {
  if (readIdentity()) throw new Error('An identity already exists on this device.')

  const displayName = normalizeName(payload.displayName, 36)
  const statusLine = normalizeName(payload.statusLine, 120)
  const passcode = payload.passcode.trim()

  if (displayName.length < 2) throw new Error('Display name must be at least 2 characters.')
  if (passcode.length < 4) throw new Error('Passcode must be at least 4 characters.')

  const now = Date.now()
  const passcodeSalt = randomBytes(16).toString('base64')

  const identity: IdentityRecord = {
    version: 1,
    profile: {
      displayName,
      statusLine: statusLine || 'Ready for a private exchange.',
      publicId: generatePublicId()
    },
    passcodeSalt,
    passcodeHash: hashPasscode(passcode, passcodeSalt),
    createdAt: now,
    updatedAt: now
  }

  writeIdentity(identity)
  isUnlocked = true
  return makeState(identity)
}

export function unlockIdentity(passcode: string): IdentityState {
  const identity = readIdentity()
  if (!identity) throw new Error('No identity found. Create one first.')

  const expected = Buffer.from(identity.passcodeHash, 'base64')
  const received = Buffer.from(hashPasscode(passcode.trim(), identity.passcodeSalt), 'base64')

  if (expected.length !== received.length || !timingSafeEqual(expected, received)) {
    throw new Error('Incorrect passcode.')
  }

  isUnlocked = true
  return makeState(identity)
}

export function lockIdentity(): IdentityState {
  isUnlocked = false
  return makeState(readIdentity())
}

export function updateIdentityProfile(payload: {
  displayName: string
  statusLine: string
}): IdentityState {
  requireUnlocked()
  const identity = readIdentity()
  if (!identity) throw new Error('No identity found.')

  const displayName = normalizeName(payload.displayName, 36)
  const statusLine = normalizeName(payload.statusLine, 120)
  if (displayName.length < 2) throw new Error('Display name must be at least 2 characters.')

  identity.profile.displayName = displayName
  identity.profile.statusLine = statusLine || 'Ready for a private exchange.'
  identity.updatedAt = Date.now()

  writeIdentity(identity)
  return makeState(identity)
}

export function regenerateIdentityPublicId(): IdentityState {
  requireUnlocked()
  const identity = readIdentity()
  if (!identity) throw new Error('No identity found.')

  identity.profile.publicId = generatePublicId()
  identity.updatedAt = Date.now()

  writeIdentity(identity)
  return makeState(identity)
}

