export type ObfuscationMethod =
  | 'direct'
  | 'https-masquerade'
  | 'domain-fronting'
  | 'steganography'
  | 'tor'

let currentMethod: ObfuscationMethod = 'direct'

export function getCurrentMethod(): ObfuscationMethod {
  return currentMethod
}

export function setMethod(method: ObfuscationMethod): void {
  currentMethod = method
}

export async function detectBlocking(): Promise<boolean> {
  // TODO Phase 3: timeout/behaviour analysis
  return false
}

export async function autoFallback(): Promise<ObfuscationMethod> {
  // TODO Phase 3: cascade HTTPS ΓåÆ fronting ΓåÆ steg ΓåÆ Tor
  return 'direct'
}

import { app } from 'electron'
import path from 'path'
import fs from 'fs'
import { randomUUID } from 'crypto'
import { requireUnlocked } from './identity'

// Using better-sqlite3 (synchronous, fast)
// Note: For production, replace with @journeyapps/sqlcipher for full AES-256-GCM encryption
let db: import('better-sqlite3').Database | null = null

export function getDbPath(): string {
  const dir = path.join(app.getPath('userData'), 'anon-chat')
  fs.mkdirSync(dir, { recursive: true })
  return path.join(dir, 'chat.db')
}

export function initStorage(): void {
  requireUnlocked()
  if (db) return

  // Dynamic require keeps native module out of renderer bundle
  const Database = require('better-sqlite3') as typeof import('better-sqlite3')
  db = new Database(getDbPath())

  db.pragma('journal_mode = WAL')
  db.pragma('foreign_keys = ON')
  db.pragma('temp_store = MEMORY')

  db.exec(`
    CREATE TABLE IF NOT EXISTS contacts (
      id           TEXT PRIMARY KEY,
      display_name TEXT NOT NULL,
      fingerprint  TEXT NOT NULL UNIQUE,
      ed_public_key TEXT NOT NULL,
      x_public_key  TEXT NOT NULL,
      note         TEXT DEFAULT '',
      is_blocked   INTEGER DEFAULT 0,
      created_at   INTEGER NOT NULL,
      last_message_at INTEGER
    );

    CREATE TABLE IF NOT EXISTS conversations (
      id              TEXT PRIMARY KEY,
      contact_id      TEXT NOT NULL,
      created_at      INTEGER NOT NULL,
      last_activity_at INTEGER,
      message_count   INTEGER DEFAULT 0,
      FOREIGN KEY (contact_id) REFERENCES contacts(id) ON DELETE CASCADE
    );

    CREATE TABLE IF NOT EXISTS messages (
      id              TEXT PRIMARY KEY,
      conversation_id TEXT NOT NULL,
      contact_id      TEXT NOT NULL,
      direction       TEXT NOT NULL CHECK(direction IN ('incoming','outgoing')),
      plaintext       TEXT NOT NULL DEFAULT '',
      delivery_status TEXT NOT NULL DEFAULT 'sent',
      message_type    TEXT NOT NULL DEFAULT 'TEXT',
      is_edited       INTEGER DEFAULT 0,
      is_deleted      INTEGER DEFAULT 0,
      created_at      INTEGER NOT NULL,
      FOREIGN KEY (conversation_id) REFERENCES conversations(id) ON DELETE CASCADE
    );

    CREATE TABLE IF NOT EXISTS session_nonces (
      id          TEXT PRIMARY KEY,
      nonce_value TEXT NOT NULL UNIQUE,
      used_at     INTEGER NOT NULL,
      expires_at  INTEGER NOT NULL
    );

    CREATE INDEX IF NOT EXISTS idx_messages_conv ON messages(conversation_id);
    CREATE INDEX IF NOT EXISTS idx_messages_contact ON messages(contact_id);
    CREATE INDEX IF NOT EXISTS idx_contacts_fp ON contacts(fingerprint);
    CREATE INDEX IF NOT EXISTS idx_nonces_exp ON session_nonces(expires_at);
  `)
}

function getDb(): import('better-sqlite3').Database {
  if (!db) throw new Error('Storage not initialized. Call initStorage() first.')
  return db
}

export function closeStorage(): void {
  if (db) {
    try { db.close() } catch { /* ignore */ }
    db = null
  }
}

// ΓöÇΓöÇ Contacts ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

export function storeContact(contact: {
  id: string
  displayName: string
  fingerprint: string
  edPublicKey: string
  xPublicKey: string
  note?: string
}): void {
  getDb()
    .prepare(`
      INSERT OR REPLACE INTO contacts
        (id, display_name, fingerprint, ed_public_key, x_public_key, note, created_at)
      VALUES (?,?,?,?,?,?,?)
    `)
    .run(
      contact.id,
      contact.displayName,
      contact.fingerprint,
      contact.edPublicKey,
      contact.xPublicKey,
      contact.note ?? '',
      Date.now()
    )
}

export function loadContacts(): unknown[] {
  return getDb()
    .prepare('SELECT * FROM contacts WHERE is_blocked = 0 ORDER BY created_at DESC')
    .all()
}

export function blockContact(id: string): void {
  getDb().prepare('UPDATE contacts SET is_blocked = 1 WHERE id = ?').run(id)
}

export function deleteContact(id: string): void {
  getDb().prepare('DELETE FROM contacts WHERE id = ?').run(id)
}

// ΓöÇΓöÇ Messages ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

export function storeMessage(msg: {
  id: string
  conversationId: string
  contactId: string
  direction: 'incoming' | 'outgoing'
  plaintext: string
  deliveryStatus?: string
}): void {
  const d = getDb()

  // Create conversation row if it doesn't exist
  d.prepare(`
    INSERT OR IGNORE INTO conversations (id, contact_id, created_at)
    VALUES (?,?,?)
  `).run(msg.conversationId, msg.contactId, Date.now())

  d.prepare(`
    INSERT INTO messages
      (id, conversation_id, contact_id, direction, plaintext, delivery_status, created_at)
    VALUES (?,?,?,?,?,?,?)
  `).run(
    msg.id,
    msg.conversationId,
    msg.contactId,
    msg.direction,
    msg.plaintext,
    msg.deliveryStatus ?? 'sent',
    Date.now()
  )

  d.prepare(`
    UPDATE conversations
    SET last_activity_at = ?, message_count = message_count + 1
    WHERE id = ?
  `).run(Date.now(), msg.conversationId)
}

export function loadMessages(conversationId: string): unknown[] {
  return getDb()
    .prepare(`
      SELECT * FROM messages
      WHERE conversation_id = ? AND is_deleted = 0
      ORDER BY created_at ASC
    `)
    .all(conversationId)
}

export function updateDeliveryStatus(
  messageId: string,
  status: 'sent' | 'delivered' | 'failed'
): void {
  getDb()
    .prepare('UPDATE messages SET delivery_status = ? WHERE id = ?')
    .run(status, messageId)
}

export function softDeleteMessage(messageId: string): void {
  getDb().prepare('UPDATE messages SET is_deleted = 1 WHERE id = ?').run(messageId)
}

// ΓöÇΓöÇ Nonce tracking ΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇΓöÇ

export function trackNonce(nonceValue: string): boolean {
  const d = getDb()
  // Purge expired nonces first
  d.prepare('DELETE FROM session_nonces WHERE expires_at < ?').run(Date.now())

  const exists = d
    .prepare('SELECT id FROM session_nonces WHERE nonce_value = ?')
    .get(nonceValue)

  if (exists) return false // Replay detected

  d.prepare(`
    INSERT INTO session_nonces (id, nonce_value, used_at, expires_at)
    VALUES (?,?,?,?)
  `).run(randomUUID(), nonceValue, Date.now(), Date.now() + 86_400_000)

  return true
}

import fs from 'fs'
import path from 'path'
import { app } from 'electron'
import { closeStorage } from './storage'
import { lockIdentity } from './identity'

export async function executeWipe(): Promise<void> {
  lockIdentity()
  closeStorage()

  const dir = path.join(app.getPath('userData'), 'anon-chat')
  if (fs.existsSync(dir)) {
    fs.rmSync(dir, { recursive: true, force: true })
  }
}

import { app, BrowserWindow, ipcMain } from 'electron'
import { join } from 'path'
import { registerIdentityIpc } from './ipc/identity.ipc'
import { registerWorkspaceIpc } from './ipc/workspace.ipc'
import { registerContactsIpc } from './ipc/contacts.ipc'
import { registerMessagesIpc } from './ipc/messages.ipc'
import { registerWipeIpc } from './ipc/wipe.ipc'

const isDev = !app.isPackaged

function createWindow(): void {
  const win = new BrowserWindow({
    width: 1360,
    height: 860,
    minWidth: 1100,
    minHeight: 700,
    backgroundColor: '#030712',
    title: 'Anon Chat',
    frame: true,
    webPreferences: {
      preload: join(__dirname, '../preload/index.js'),
      contextIsolation: true,
      nodeIntegration: false,
      sandbox: true
    }
  })

  // Register all IPC handlers before loading UI
  registerIdentityIpc(ipcMain)
  registerWorkspaceIpc(ipcMain)
  registerContactsIpc(ipcMain)
  registerMessagesIpc(ipcMain)
  registerWipeIpc(ipcMain)

  if (isDev) {
    win.loadURL('http://localhost:5173')
    win.webContents.openDevTools({ mode: 'detach' })
  } else {
    win.loadFile(join(__dirname, '../renderer/index.html'))
  }
}

app.whenReady().then(() => {
  createWindow()
  app.on('activate', () => {
    if (BrowserWindow.getAllWindows().length === 0) createWindow()
  })
})

app.on('window-all-closed', () => {
  if (process.platform !== 'darwin') app.quit()
})

import type { IpcMain } from 'electron'
import { z } from 'zod'
import { randomUUID } from 'crypto'
import { requireUnlocked } from '../core/identity'
import { storeContact, loadContacts, deleteContact, blockContact } from '../core/storage'
import { computeFingerprint } from '../core/cryptography'

const AddContactSchema = z.object({
  displayName: z.string().min(1).max(60),
  edPublicKey: z.string().min(10),
  xPublicKey: z.string().min(10),
  note: z.string().max(200).optional().default('')
})

export function registerContactsIpc(ipcMain: IpcMain): void {
  ipcMain.handle('contacts:list', () => {
    requireUnlocked()
    return loadContacts()
  })

  ipcMain.handle('contacts:add', (_, payload: unknown) => {
    requireUnlocked()
    const parsed = AddContactSchema.parse(payload)
    const fingerprint = computeFingerprint(parsed.edPublicKey, parsed.xPublicKey)
    const contact = {
      id: randomUUID(),
      displayName: parsed.displayName,
      fingerprint,
      edPublicKey: parsed.edPublicKey,
      xPublicKey: parsed.xPublicKey,
      note: parsed.note
    }
    storeContact(contact)
    return { ...contact }
  })

  ipcMain.handle('contacts:delete', (_, id: unknown) => {
    requireUnlocked()
    if (typeof id !== 'string') throw new Error('Invalid contact id')
    deleteContact(id)
    return { ok: true }
  })

  ipcMain.handle('contacts:block', (_, id: unknown) => {
    requireUnlocked()
    if (typeof id !== 'string') throw new Error('Invalid contact id')
    blockContact(id)
    return { ok: true }
  })
}

import type { IpcMain } from 'electron'
import { z } from 'zod'
import {
  getIdentityState,
  createIdentity,
  unlockIdentity,
  lockIdentity,
  updateIdentityProfile,
  regenerateIdentityPublicId
} from '../core/identity'

const CreateIdentitySchema = z.object({
  displayName: z.string().min(2).max(36),
  statusLine: z.string().max(120),
  passcode: z.string().min(4)
})

const UnlockIdentitySchema = z.object({
  passcode: z.string().min(1)
})

const UpdateProfileSchema = z.object({
  displayName: z.string().min(2).max(36),
  statusLine: z.string().max(120)
})

export function registerIdentityIpc(ipcMain: IpcMain): void {
  ipcMain.handle('identity:get-state', () => getIdentityState())

  ipcMain.handle('identity:create', (_, payload: unknown) => {
    const parsed = CreateIdentitySchema.parse(payload)
    return createIdentity(parsed)
  })

  ipcMain.handle('identity:unlock', (_, payload: unknown) => {
    const parsed = UnlockIdentitySchema.parse(payload)
    return unlockIdentity(parsed.passcode)
  })

  ipcMain.handle('identity:lock', () => lockIdentity())

  ipcMain.handle('identity:update-profile', (_, payload: unknown) => {
    const parsed = UpdateProfileSchema.parse(payload)
    return updateIdentityProfile(parsed)
  })

  ipcMain.handle('identity:regenerate-id', () => regenerateIdentityPublicId())
}

import type { IpcMain } from 'electron'
import { z } from 'zod'
import { randomUUID } from 'crypto'
import { requireUnlocked } from '../core/identity'
import { storeMessage, loadMessages, softDeleteMessage, updateDeliveryStatus } from '../core/storage'

const SendSchema = z.object({
  contactId: z.string().uuid(),
  conversationId: z.string().min(1),
  text: z.string().min(1).max(10_000)
})

const StatusSchema = z.object({
  messageId: z.string().uuid(),
  status: z.enum(['sent', 'delivered', 'failed'])
})

export function registerMessagesIpc(ipcMain: IpcMain): void {
  ipcMain.handle('messages:load', (_, conversationId: unknown) => {
    requireUnlocked()
    if (typeof conversationId !== 'string') throw new Error('Invalid conversationId')
    return loadMessages(conversationId)
  })

  ipcMain.handle('messages:send', (_, payload: unknown) => {
    requireUnlocked()
    const { contactId, conversationId, text } = SendSchema.parse(payload)
    const msg = {
      id: randomUUID(),
      conversationId,
      contactId,
      direction: 'outgoing' as const,
      plaintext: text,
      deliveryStatus: 'sent'
    }
    storeMessage(msg)
    return msg
  })

  ipcMain.handle('messages:delete', (_, messageId: unknown) => {
    requireUnlocked()
    if (typeof messageId !== 'string') throw new Error('Invalid messageId')
    softDeleteMessage(messageId)
    return { ok: true }
  })

  ipcMain.handle('messages:update-status', (_, payload: unknown) => {
    requireUnlocked()
    const { messageId, status } = StatusSchema.parse(payload)
    updateDeliveryStatus(messageId, status)
    return { ok: true }
  })
}

