import { useState, FormEvent } from 'react'
import { ShieldCheck, User, Lock, ChevronRight, ChevronLeft } from 'lucide-react'

export default function OnboardingPage({ onCreated }: { onCreated: () => void }) {
  const [step, setStep]             = useState<1 | 2>(1)
  const [displayName, setName]      = useState('')
  const [statusLine, setStatus]     = useState('')
  const [passcode, setPasscode]     = useState('')
  const [confirm, setConfirm]       = useState('')
  const [error, setError]           = useState('')
  const [loading, setLoading]       = useState(false)

  async function handleCreate(e: FormEvent) {
    e.preventDefault()
    setError('')
    if (passcode !== confirm) { setError('Passcodes do not match'); return }
    if (passcode.length < 4)  { setError('Passcode must be at least 4 characters'); return }
    setLoading(true)
    try {
      await window.api.createIdentity({ displayName, statusLine, passcode })
      await window.api.initWorkspace()
      onCreated()
    } catch (err: unknown) {
      setError(err instanceof Error ? err.message : 'Failed to create identity')
    } finally {
      setLoading(false)
    }
  }

  return (
    <div className="flex h-screen bg-gray-950 items-center justify-center">
      <div className="w-full max-w-sm px-8">
        <div className="flex flex-col items-center mb-10">
          <div className="p-4 rounded-2xl bg-teal-500/10 border border-teal-500/20 mb-4">
            <ShieldCheck className="w-10 h-10 text-teal-400" />
          </div>
          <h1 className="text-2xl font-semibold text-white">Create Your Identity</h1>
          <p className="text-gray-500 text-sm mt-1 text-center">
            Zero registration ┬╖ No phone ┬╖ No email
          </p>

          {/* Step indicators */}
          <div className="flex gap-2 mt-4">
            {[1, 2].map((s) => (
              <div
                key={s}
                className={`h-1 w-8 rounded-full transition-colors ${
                  s === step ? 'bg-teal-500' : 'bg-gray-700'
                }`}
              />
            ))}
          </div>
        </div>

        {step === 1 && (
          <div className="space-y-4">
            <div>
              <label className="block text-xs font-medium text-gray-400 mb-2 uppercase tracking-wider">
                Display Name
              </label>
              <div className="relative">
                <User className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-gray-500" />
                <input
                  type="text"
                  value={displayName}
                  onChange={(e) => setName(e.target.value)}
                  placeholder="e.g. Cipher Ghost"
                  maxLength={36}
                  className="w-full bg-gray-900 border border-gray-800 focus:border-teal-500 rounded-xl pl-10 pr-4 py-3 text-white placeholder-gray-600 outline-none transition-colors"
                  autoFocus
                />
              </div>
            </div>

            <div>
              <label className="block text-xs font-medium text-gray-400 mb-2 uppercase tracking-wider">
                Status Line <span className="text-gray-600 normal-case">(optional)</span>
              </label>
              <input
                type="text"
                value={statusLine}
                onChange={(e) => setStatus(e.target.value)}
                placeholder="Ready for a private exchange."
                maxLength={120}
                className="w-full bg-gray-900 border border-gray-800 focus:border-teal-500 rounded-xl px-4 py-3 text-white placeholder-gray-600 outline-none transition-colors"
              />
            </div>

            <button
              onClick={() => { if (displayName.trim().length >= 2) setStep(2) }}
              disabled={displayName.trim().length < 2}
              className="w-full flex items-center justify-center gap-2 bg-teal-600 hover:bg-teal-500 disabled:bg-gray-800 disabled:text-gray-600 text-white rounded-xl py-3 font-medium transition-colors"
            >
              Continue <ChevronRight className="w-4 h-4" />
            </button>
          </div>
        )}

        {step === 2 && (
          <form onSubmit={handleCreate} className="space-y-4">
            <div>
              <label className="block text-xs font-medium text-gray-400 mb-2 uppercase tracking-wider">
                Passcode
              </label>
              <div className="relative">
                <Lock className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-gray-500" />
                <input
                  type="password"
                  value={passcode}
                  onChange={(e) => setPasscode(e.target.value)}
                  placeholder="Min 4 characters"
                  className="w-full bg-gray-900 border border-gray-800 focus:border-teal-500 rounded-xl pl-10 pr-4 py-3 text-white placeholder-gray-600 outline-none transition-colors"
                  autoFocus
                />
              </div>
            </div>

            <div>
              <label className="block text-xs font-medium text-gray-400 mb-2 uppercase tracking-wider">
                Confirm Passcode
              </label>
              <div className="relative">
                <Lock className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-gray-500" />
                <input
                  type="password"
                  value={confirm}
                  onChange={(e) => setConfirm(e.target.value)}
                  placeholder="Re-enter passcode"
                  className="w-full bg-gray-900 border border-gray-800 focus:border-teal-500 rounded-xl pl-10 pr-4 py-3 text-white placeholder-gray-600 outline-none transition-colors"
                />
              </div>
            </div>

            {error && (
              <p className="text-sm text-red-400 bg-red-950/30 border border-red-900/40 rounded-lg px-3 py-2">
                {error}
              </p>
            )}

            <div className="flex gap-3">
              <button
                type="button"
                onClick={() => setStep(1)}
                className="flex items-center gap-1 px-4 py-3 bg-gray-800 hover:bg-gray-700 text-gray-300 rounded-xl font-medium transition-colors"
              >
                <ChevronLeft className="w-4 h-4" />
              </button>
              <button
                type="submit"
                disabled={loading || !passcode || !confirm}
                className="flex-1 bg-teal-600 hover:bg-teal-500 disabled:bg-gray-800 disabled:text-gray-600 text-white rounded-xl py-3 font-medium transition-colors"
              >
                {loading ? 'Creating...' : 'Create Identity'}
              </button>
            </div>
          </form>
        )}

        <p className="text-center text-gray-700 text-xs mt-8">
          Your keys are generated locally and never leave this device.
        </p>
      </div>
    </div>
  )
}

import { useEffect, useState } from 'react'
import { Settings, LogOut, Flame, RefreshCw, Save } from 'lucide-react'
import AppLayout from '../components/AppLayout'

interface Profile { displayName: string; statusLine: string; publicId: string }

export default function SettingsPage({ onLocked }: { onLocked: () => void }) {
  const [profile, setProfile]   = useState<Profile | null>(null)
  const [name, setName]         = useState('')
  const [status, setStatus]     = useState('')
  const [wipeText, setWipeText] = useState('')
  const [saving, setSaving]     = useState(false)
  const [wiping, setWiping]     = useState(false)
  const [saved, setSaved]       = useState(false)
  const [error, setError]       = useState('')

  useEffect(() => {
    window.api.getWorkspaceSummary().then((s) => {
      setProfile(s.profile)
      setName(s.profile.displayName)
      setStatus(s.profile.statusLine)
    })
  }, [])

  async function handleSave() {
    setSaving(true); setSaved(false); setError('')
    try {
      await window.api.updateIdentityProfile({ displayName: name, statusLine: status })
      setSaved(true)
      setTimeout(() => setSaved(false), 2000)
    } catch (err: unknown) {
      setError(err instanceof Error ? err.message : 'Failed to save')
    } finally {
      setSaving(false)
    }
  }

  async function handleLock() {
    await window.api.lockIdentity()
    onLocked()
  }

  async function handleWipe() {
    if (wipeText !== 'DESTROY') return
    setWiping(true)
    await window.api.executeWipe({ confirmation: 'DESTROY' })
  }

  return (
    <AppLayout>
      <div className="h-full flex flex-col">
        <div className="px-6 py-4 border-b border-gray-800 flex items-center gap-3">
          <Settings className="w-5 h-5 text-gray-400" />
          <h1 className="text-lg font-semibold text-white">Settings</h1>
        </div>

        <div className="flex-1 overflow-y-auto px-6 py-6 space-y-8 max-w-lg">
          {/* Profile */}
          <section>
            <h2 className="text-xs font-semibold text-gray-500 uppercase tracking-wider mb-4">Profile</h2>
            <div className="space-y-3">
              <div>
                <label className="block text-xs text-gray-400 mb-1.5">Display Name</label>
                <input
                  value={name}
                  onChange={(e) => setName(e.target.value)}
                  maxLength={36}
                  className="w-full bg-gray-900 border border-gray-800 focus:border-teal-500 rounded-xl px-4 py-2.5 text-white outline-none text-sm transition-colors"
                />
              </div>
              <div>
                <label className="block text-xs text-gray-400 mb-1.5">Status Line</label>
                <input
                  value={status}
                  onChange={(e) => setStatus(e.target.value)}
                  maxLength={120}
                  className="w-full bg-gray-900 border border-gray-800 focus:border-teal-500 rounded-xl px-4 py-2.5 text-white outline-none text-sm transition-colors"
                />
              </div>
              {error && <p className="text-red-400 text-xs">{error}</p>}
              <button
                onClick={handleSave}
                disabled={saving}
                className="flex items-center gap-2 bg-teal-600 hover:bg-teal-500 disabled:bg-gray-800 text-white px-4 py-2.5 rounded-xl text-sm font-medium transition-colors"
              >
                <Save className="w-4 h-4" />
                {saved ? 'Saved!' : saving ? 'Saving...' : 'Save Changes'}
              </button>
            </div>
          </section>

          {/* Identity info */}
          {profile && (
            <section>
              <h2 className="text-xs font-semibold text-gray-500 uppercase tracking-wider mb-4">Identity</h2>
              <div className="bg-gray-900 border border-gray-800 rounded-xl px-4 py-3 space-y-2">
                <div className="flex justify-between text-sm">
                  <span className="text-gray-500">Public ID</span>
                  <span className="text-gray-300 font-mono text-xs">{profile.publicId}</span>
                </div>
                <button
                  onClick={async () => { await window.api.regenerateIdentityId(); window.location.reload() }}
                  className="flex items-center gap-1.5 text-xs text-gray-500 hover:text-teal-400 transition-colors"
                >
                  <RefreshCw className="w-3 h-3" /> Regenerate Public ID
                </button>
              </div>
            </section>
          )}

          {/* Session */}
          <section>
            <h2 className="text-xs font-semibold text-gray-500 uppercase tracking-wider mb-4">Session</h2>
            <button
              onClick={handleLock}
              className="flex items-center gap-2 bg-gray-800 hover:bg-gray-700 text-gray-300 px-4 py-2.5 rounded-xl text-sm font-medium transition-colors"
            >
              <LogOut className="w-4 h-4" /> Lock Application
            </button>
          </section>

          {/* Emergency wipe */}
          <section>
            <h2 className="text-xs font-semibold text-red-900 uppercase tracking-wider mb-4">
              Danger Zone
            </h2>
            <div className="bg-red-950/20 border border-red-900/40 rounded-xl p-4 space-y-3">
              <div className="flex items-start gap-3">
                <Flame className="w-5 h-5 text-red-500 flex-shrink-0 mt-0.5" />
                <div>
                  <p className="text-sm font-medium text-red-400">Burn Account</p>
                  <p className="text-xs text-red-900/80 mt-1">
                    Permanently destroys all keys, messages, and contacts using a 7-pass DoD overwrite.
                    This action is <strong className="text-red-500">irreversible</strong>.
                  </p>
                </div>
              </div>
              <input
                type="text"
                value={wipeText}
                onChange={(e) => setWipeText(e.target.value)}
                placeholder='Type "DESTROY" to confirm'
                className="w-full bg-gray-950 border border-red-900/40 focus:border-red-700 rounded-lg px-3 py-2 text-red-300 placeholder-red-900/60 outline-none text-sm font-mono transition-colors"
              />
              <button
                onClick={handleWipe}
                disabled={wipeText !== 'DESTROY' || wiping}
                className="w-full bg-red-900/40 hover:bg-red-800/60 disabled:opacity-30 disabled:cursor-not-allowed text-red-400 border border-red-900/60 rounded-lg py-2.5 text-sm font-medium transition-colors"
              >
                {wiping ? 'Wiping...' : 'Burn Account ΓÇö Destroy All Data'}
              </button>
            </div>
          </section>
        </div>
      </div>
    </AppLayout>
  )
}

import type { ReactElement } from 'react'
import { useEffect, useState } from 'react'
import { Copy, RefreshCw, Share2 } from 'lucide-react'
import AppLayout from '../components/AppLayout'
import QRDisplay from '../components/QRDisplay'

interface Profile { displayName: string; publicId: string }

export default function SharePage(): ReactElement {
  const [profile, setProfile] = useState<Profile | null>(null)
  const [copied, setCopied]   = useState(false)

  async function load(): Promise<void> {
    const s = await window.api.getWorkspaceSummary()
    setProfile(s.profile)
  }

  useEffect(() => {
    const fetchProfile = async (): Promise<void> => {
      const s = await window.api.getWorkspaceSummary()
      setProfile(s.profile)
    }

    void fetchProfile()
  }, [])

  async function handleRegenerate(): Promise<void> {
    if (!confirm('Regenerate your public ID? Existing contacts will not be affected.')) return
    await window.api.regenerateIdentityId()
    await load()
  }

  function handleCopy(): void {
    if (!profile) return
    void navigator.clipboard.writeText(profile.publicId)
    setCopied(true)
    setTimeout(() => setCopied(false), 2000)
  }

  const qrData = profile ? JSON.stringify({ publicId: profile.publicId, displayName: profile.displayName }) : ''

  return (
    <AppLayout>
      <div className="h-full flex flex-col">
        <div className="px-6 py-4 border-b border-gray-800 flex items-center gap-3">
          <Share2 className="w-5 h-5 text-gray-400" />
          <h1 className="text-lg font-semibold text-white">Share Identity</h1>
        </div>

        <div className="flex-1 flex flex-col items-center justify-center gap-8 px-6">
          {profile && (
            <>
              <div className="text-center">
                <p className="text-gray-400 text-sm mb-1">{profile.displayName}</p>
                <p className="text-xs text-gray-600 font-mono">{profile.publicId}</p>
              </div>

              <QRDisplay data={qrData} size={220} />

              <div className="flex gap-3">
                <button
                  onClick={handleCopy}
                  className="flex items-center gap-2 bg-gray-800 hover:bg-gray-700 text-gray-300 px-4 py-2.5 rounded-lg text-sm font-medium transition-colors"
                >
                  <Copy className="w-4 h-4" />
                  {copied ? 'Copied!' : 'Copy ID'}
                </button>
                <button
                  onClick={handleRegenerate}
                  className="flex items-center gap-2 bg-gray-800 hover:bg-gray-700 text-gray-300 px-4 py-2.5 rounded-lg text-sm font-medium transition-colors"
                >
                  <RefreshCw className="w-4 h-4" /> Regenerate
                </button>
              </div>

              <p className="text-gray-600 text-xs text-center max-w-xs">
                Ask your contact to scan this QR code, or share your Public ID manually.
                No personal data is embedded.
              </p>
            </>
          )}
        </div>
      </div>
    </AppLayout>
  )
}
